import { useState, useMemo } from "react";
import { useAppStore } from "../store/appStore";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import { useBacktestResults } from "../contexts/BacktestResultsContext";
import V2EmptyState from "../components/V2EmptyState";

/* -- scenario presets ---------------------------------------- */
const PRESETS = {
  custom:    { label: "Custom",      equity: 5,  vol: 2, rate: 1,  desc: "User-defined scenario" },
  crisis08:  { label: "2008 Crisis", equity: 28, vol: 5, rate: 2,  desc: "Lehman collapse, -38% SPX, VIX 80" },
  covid:     { label: "COVID Crash", equity: 22, vol: 4, rate: 0,  desc: "Mar 2020, -34% SPX in 23 days" },
  rateHike:  { label: "Rate Hike",   equity: 8,  vol: 2, rate: 4,  desc: "Aggressive Fed tightening cycle" },
  techWreck: { label: "Tech Wreck",  equity: 15, vol: 3, rate: 1,  desc: "2022-style tech rotation, NASDAQ -33%" },
};

/* -- stat card ----------------------------------------------- */
function Stat({ label, value, t = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${t}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* -- main page ----------------------------------------------- */
export default function WhatIf() {
  const { state } = useAppStore();
  const [activePreset, setActivePreset] = useState("custom");
  const [equityShock, setEquityShock] = useState(5);
  const [volShock, setVolShock] = useState(2);
  const [rateShock, setRateShock] = useState(1);

  /* fetch bot data from risk/exposure (no auth needed) + v2/what-if scenarios */
  const { data: botConfig } = usePoll(
    async () => {
      /* Try /bots first (needs auth), fall back to /risk/exposure */
      let bots = null;
      const PAPER_BOTS = new Set(['layla', 'paper', 'demo']);
      try {
        const r = await http.get("/bots");
        bots = (r.data?.bots || []).filter(b => !PAPER_BOTS.has((b.bot_name || '').toLowerCase())).map(b => ({
          name: (b.display_name || b.bot_name || '').toUpperCase(),
          exposure: b.equity?.current || b.positions_value || 0,
          currentPnl: b.equity?.day || b.equity?.day_pnl || 0,
          beta: 1.0,
        }));
      } catch {
        /* fallback: use risk/exposure which is unauthenticated */
        const r = await http.get("/risk/exposure");
        bots = (r.data?.exposure || []).filter(b => !PAPER_BOTS.has((b.bot_name || '').toLowerCase())).map(b => ({
          name: (b.bot_name || '').toUpperCase(),
          exposure: b.equity || Math.abs(b.positions_value || 0),
          currentPnl: 0,
          beta: 1.0,
        }));
      }
      return bots;
    },
    { intervalMs: 60000, immediate: true, enabled: !state.offlineMode }
  );
  const BOTS = useMemo(() => {
    if (!botConfig || botConfig.length === 0) return [];
    return botConfig;
  }, [botConfig]);

  /* backtest results from shared context */
  const { results: btData, loading } = useBacktestResults();

  /* apply preset */
  const applyPreset = (key) => {
    setActivePreset(key);
    const p = PRESETS[key];
    setEquityShock(p.equity);
    setVolShock(p.vol);
    setRateShock(p.rate);
  };

  /* compute stressed results */
  const results = useMemo(() => {
    return BOTS.map(bot => {
      const equityImpact = -bot.exposure * (equityShock / 100) * bot.beta;
      const volImpact = -bot.exposure * 0.02 * (volShock - 1);
      const rateImpact = -bot.exposure * 0.005 * rateShock;
      const stressedPnl = bot.currentPnl + equityImpact + volImpact + rateImpact;
      const delta = stressedPnl - bot.currentPnl;
      const breached = stressedPnl < -(bot.exposure * 0.08);
      return { ...bot, stressedPnl, delta, breached };
    });
  }, [BOTS, equityShock, volShock, rateShock]);

  const totalCurrent = results.reduce((a, b) => a + b.currentPnl, 0);
  const totalStressed = results.reduce((a, b) => a + b.stressedPnl, 0);
  const totalDelta = totalStressed - totalCurrent;
  const totalExposure = BOTS.reduce((a, b) => a + b.exposure, 0);
  const breachCount = results.filter(r => r.breached).length;
  const marginCallRisk = totalExposure > 0 && totalStressed < -(totalExposure * 0.1);

  const fmtUsd = (v) => `${v < 0 ? "-" : "+"}$${Math.abs(v).toLocaleString("en-US", { minimumFractionDigits: 0 })}`;

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">What-If Scenarios</h1>
            <div className="v2-muted">Loading scenario data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1,2,3,4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  return (
    <>
      {/* -- header -------------------------------------------- */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">What-If Scenarios</h1>
          <div className="v2-muted">Stress testing with dynamic sliders. Simulate equity crashes, volatility spikes, and rate shocks.</div>
        </div>
      </div>

      {/* -- scenario presets ---------------------------------- */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Scenario Presets</div>
          <div className="v2-row" style={{ marginTop: 8 }}>
            {Object.entries(PRESETS).map(([key, p]) => (
              <button
                key={key}
                className="v2-btn"
                onClick={() => applyPreset(key)}
                style={activePreset === key ? {
                  background: key === "crisis08" ? "rgba(255,120,120,0.15)" :
                              key === "covid" ? "rgba(255,210,120,0.15)" :
                              key === "rateHike" ? "rgba(150,190,255,0.15)" :
                              key === "techWreck" ? "rgba(188,140,255,0.15)" :
                              "rgba(255,255,255,0.08)",
                  borderColor: key === "crisis08" ? "rgba(255,120,120,0.3)" :
                               key === "covid" ? "rgba(255,210,120,0.3)" :
                               key === "rateHike" ? "rgba(150,190,255,0.3)" :
                               key === "techWreck" ? "rgba(188,140,255,0.3)" :
                               "rgba(255,255,255,0.15)",
                } : {}}
              >
                {p.label}
              </button>
            ))}
          </div>
          <div className="v2-muted" style={{ marginTop: 8 }}>
            {PRESETS[activePreset].desc}
          </div>
        </div>
      </div>

      {/* -- stress sliders ------------------------------------ */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card third">
          <div className="v2-ct">Equity Shock</div>
          <div className="v2-cv v2-red" style={{ fontSize: 28 }}>-{equityShock}%</div>
          <input
            className="v2-input"
            type="range" min="0" max="30" value={equityShock}
            onChange={(e) => { setEquityShock(parseInt(e.target.value, 10)); setActivePreset("custom"); }}
            style={{ width: "100%", marginTop: 12, cursor: "pointer" }}
          />
          <div className="v2-row" style={{ justifyContent: "space-between", marginTop: 8 }}>
            <span className="v2-muted" style={{ fontSize: 11 }}>0%</span>
            <span className="v2-muted" style={{ fontSize: 11 }}>-30%</span>
          </div>
          <div className="v2-muted" style={{ marginTop: 4, fontSize: 11 }}>Broad market decline magnitude</div>
        </div>

        <div className="v2-card third">
          <div className="v2-ct">Volatility Shock</div>
          <div className="v2-cv v2-amber" style={{ fontSize: 28 }}>{volShock}x</div>
          <input
            className="v2-input"
            type="range" min="1" max="5" value={volShock}
            onChange={(e) => { setVolShock(parseInt(e.target.value, 10)); setActivePreset("custom"); }}
            style={{ width: "100%", marginTop: 12, cursor: "pointer" }}
          />
          <div className="v2-row" style={{ justifyContent: "space-between", marginTop: 8 }}>
            <span className="v2-muted" style={{ fontSize: 11 }}>1x</span>
            <span className="v2-muted" style={{ fontSize: 11 }}>5x</span>
          </div>
          <div className="v2-muted" style={{ marginTop: 4, fontSize: 11 }}>VIX multiplier (1x = current)</div>
        </div>

        <div className="v2-card third">
          <div className="v2-ct">Rate Shock</div>
          <div className="v2-cv v2-blue" style={{ fontSize: 28 }}>+{rateShock}%</div>
          <input
            className="v2-input"
            type="range" min="0" max="5" value={rateShock}
            onChange={(e) => { setRateShock(parseInt(e.target.value, 10)); setActivePreset("custom"); }}
            style={{ width: "100%", marginTop: 12, cursor: "pointer" }}
          />
          <div className="v2-row" style={{ justifyContent: "space-between", marginTop: 8 }}>
            <span className="v2-muted" style={{ fontSize: 11 }}>0%</span>
            <span className="v2-muted" style={{ fontSize: 11 }}>+5%</span>
          </div>
          <div className="v2-muted" style={{ marginTop: 4, fontSize: 11 }}>Interest rate increase (bps)</div>
        </div>
      </div>

      {/* -- impact results table ------------------------------ */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Stress Impact by Bot</div>
          {BOTS.length === 0 ? (
            <V2EmptyState title="No Bot Data" message="Waiting for bot configuration from the API to compute stress impacts." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "100px 120px 120px 120px 80px 1fr" }}>
                <span>Bot</span>
                <span style={{ textAlign: "right" }}>Current PnL</span>
                <span style={{ textAlign: "right" }}>Stressed PnL</span>
                <span style={{ textAlign: "right" }}>Delta</span>
                <span style={{ textAlign: "center" }}>Breach?</span>
                <span>Impact Bar</span>
              </div>
              {results.map(r => (
                <div key={r.name} className="v2-tr" style={{
                  gridTemplateColumns: "100px 120px 120px 120px 80px 1fr",
                  alignItems: "center",
                  background: r.breached ? "rgba(255,120,120,0.06)" : "transparent",
                }}>
                  <span style={{ fontWeight: 600 }}>{r.name}</span>
                  <span className={`v2-mono v2-${r.currentPnl >= 0 ? "green" : "red"}`} style={{ textAlign: "right" }}>
                    {fmtUsd(r.currentPnl)}
                  </span>
                  <span className={`v2-mono v2-${r.stressedPnl >= 0 ? "green" : "red"}`} style={{ textAlign: "right" }}>
                    {fmtUsd(r.stressedPnl)}
                  </span>
                  <span className="v2-mono v2-red" style={{ textAlign: "right" }}>
                    {fmtUsd(r.delta)}
                  </span>
                  <span style={{ textAlign: "center" }}>
                    {r.breached
                      ? <span className="v2-pill v2-red" style={{ fontSize: 10 }}>YES</span>
                      : <span className="v2-pill v2-green" style={{ fontSize: 10 }}>NO</span>
                    }
                  </span>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <div style={{ flex: 1, height: 8, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                      <div style={{
                        height: "100%",
                        width: `${r.exposure > 0 ? Math.min(Math.abs(r.delta) / (r.exposure * 0.3) * 100, 100) : 0}%`,
                        borderRadius: 6,
                        background: r.breached
                          ? "linear-gradient(90deg, rgba(255,120,120,0.7), rgba(255,120,120,0.3))"
                          : "linear-gradient(90deg, rgba(255,210,120,0.5), rgba(255,120,120,0.3))",
                        transition: "width 0.25s ease",
                      }} />
                    </div>
                  </div>
                </div>
              ))}
              {/* Total row */}
              <div className="v2-tr" style={{
                gridTemplateColumns: "100px 120px 120px 120px 80px 1fr",
                borderTop: "1px solid rgba(255,255,255,0.12)",
                background: "rgba(255,255,255,0.02)",
              }}>
                <span style={{ fontWeight: 800 }}>TOTAL</span>
                <span className={`v2-mono v2-${totalCurrent >= 0 ? "green" : "red"}`} style={{ textAlign: "right", fontWeight: 700 }}>
                  {fmtUsd(totalCurrent)}
                </span>
                <span className={`v2-mono v2-${totalStressed >= 0 ? "green" : "red"}`} style={{ textAlign: "right", fontWeight: 700 }}>
                  {fmtUsd(totalStressed)}
                </span>
                <span className="v2-mono v2-red" style={{ textAlign: "right", fontWeight: 700 }}>
                  {fmtUsd(totalDelta)}
                </span>
                <span style={{ textAlign: "center" }}>
                  <span className={`v2-pill v2-${breachCount > 0 ? "red" : "green"}`} style={{ fontSize: 10 }}>
                    {breachCount}
                  </span>
                </span>
                <span />
              </div>
            </div>
          )}
        </div>
      </div>

      {/* -- portfolio impact summary -------------------------- */}
      {BOTS.length > 0 && (
        <div className="v2-grid" style={{ marginBottom: 16 }}>
          <Stat
            label="Total Loss Estimate"
            value={fmtUsd(totalDelta)}
            t="red"
            sub={totalExposure > 0 ? `${((totalDelta / totalExposure) * 100).toFixed(1)}% of gross exposure` : "--"}
          />
          <Stat
            label="Margin Call Risk"
            value={marginCallRisk ? "HIGH" : "LOW"}
            t={marginCallRisk ? "red" : "green"}
            sub={marginCallRisk ? "Stressed PnL exceeds 10% threshold" : "Within margin tolerance"}
          />
          <Stat
            label="Limit Breaches"
            value={breachCount}
            t={breachCount > 0 ? "red" : "green"}
            sub={`${breachCount} of ${BOTS.length} bots breach 8% gate`}
          />
          <Stat
            label="Recovery Estimate"
            value={equityShock > 20 ? "6-14 mo" : equityShock > 10 ? "3-8 mo" : "1-3 mo"}
            t="amber"
            sub="Based on historical drawdown recovery"
          />
        </div>
      )}

      {/* -- recommended actions + historical ------------------ */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card half">
          <div className="v2-ct">Recommended Risk Actions</div>
          <V2EmptyState title="No Recommendations" message="Risk action recommendations will appear when the API provides them based on current portfolio state." />
        </div>

        <div className="v2-card half">
          <div className="v2-ct">Historical Scenario Comparison</div>
          <V2EmptyState title="No Historical Data" message="Historical scenario comparison data will appear when available from the API." />
        </div>
      </div>
    </>
  );
}
